export interface Artist {
  slug: string;
  name: string;
  bio: string;
  curationComment: string;
  artistQuote?: string;
  essayUrl?: string;
  essayTitle?: string;
  website?: string;
  twitter?: string;
  instagram?: string;
  /** Path to a small identity image - portrait, signature avatar, or icon
      that best depicts the artist (XCOPY's signature avatar, Tyler Hobbs's
      portrait, Operator's masked image, etc.). Rendered as a small badge
      on the artist page next to the holdings count line and on the
      Artists index next to the name. Recommended: square crop, served at
      ~256px source so it stays sharp at 32-64px display sizes. Path is
      relative to /public (e.g., "/artists/xcopy.png"). Optional - when
      absent the badge slot is skipped entirely. */
  portrait?: string;
  influences: string[];
  tags: string[];
}

export interface Exhibition {
  /** Year or month-year, e.g. "2021" or "October 2024" */
  date: string;
  /** Exhibition or event title - italicized in render. */
  title: string;
  /** City or venue, rendered after the title. */
  location?: string;
  /** Optional link to event details (press, recap, catalogue). Renders the
      title + location as an external link when present. */
  url?: string;
}

export interface Collection {
  slug: string;
  name: string;
  artistSlug: string;
  description: string;
  /** Verbatim quote from the artist about this collection (e.g. the OpenSea
      "About" copy when the artist wrote it themselves). Optional - included
      where the artist's voice adds depth alongside the factual description
      and Hivemind's curator commentary. Whitespace and line breaks are
      preserved at render time so free-verse poems read as the artist set
      them. */
  artistStatement?: string;
  /** When true, the per-piece description metadata is suppressed for every
      piece in this collection - the artistStatement at the collection level
      covers them and per-piece repetition would be noise. Used for collections
      like Ringers where the on-chain description is identical across every
      token and reads as the artist's explanation of the algorithm, not as
      per-piece context. */
  suppressPieceDescriptions?: boolean;
  curatorNote: string;
  essayUrl?: string;
  essayTitle?: string;
  medium: 'image' | 'video' | 'generative' | 'interactive';
  contractAddress?: string;
  totalSupply?: number;
  mintDate?: string;
  /** On-chain code size in kilobytes, for collections where the artwork is
      fully on-chain and the storage footprint is editorially relevant
      (Asendorf's Lights at 11 Kb is a small-footprint generative work).
      Surfaced as a quiet metadata line next to mintDate; absent for
      collections where code size isn't a meaningful signal. */
  codeSizeKb?: number;
  /** Platform / marketplace where the collection was minted - surfaced as
      a quiet data row alongside Contract / Type. Useful for institutional
      readers where the platform name carries provenance weight (SuperRare
      curated 1/1s, Async Art for the Grifters, etc.). */
  platform?: string;
  /** Public exhibitions / auctions / showings of works in this collection. */
  exhibitions?: Exhibition[];
  /** Single-line institutional note about the Fund's position in this
      collection (e.g. "DCF is the largest single holder..."). Surfaces on
      every piece page in the collection as a quiet eyebrow, and on the
      collection page itself. */
  holdingNote?: string;
  tags: string[];
  influences: string[];
}

export interface Piece {
  id: string;
  slug: string;
  title: string;
  collectionSlug: string;
  artistSlug: string;
  image: string;
  medium: 'image' | 'video' | 'generative' | 'interactive';
  description: string;
  traits: Record<string, string>;
  tokenId?: string;
  contractAddress?: string;
  mintDate?: string;
  lastSalePrice?: string;
  floorPrice?: string;
  influences: string[];
  openseaUrl?: string;
  // Optional deep-link to the work on the artist's own website
  // (e.g. https://xcopy.art/..., https://ack.art/...). The "View on {host}"
  // link on the piece page is derived from this URL's hostname.
  artistSiteUrl?: string;
  // Original source URI for the artwork - usually IPFS or Arweave.
  // Rendered as a "View original on ipfs.io" link on the piece page.
  // ipfs:// and ar:// URIs are resolved to public gateways at render time.
  originalUri?: string;
  // Physical specifications for sculptural / installation works that have
  // no on-chain token. Rendered as a Specifications panel on the piece
  // page (in lieu of the blockchain details panel which is omitted for
  // pieces without a contract/token).
  physical?: {
    dimensions: string;
    weight?: string;
    materials: string;
    edition?: string;
  };
  // Slug of a related piece in the catalogue (e.g. the on-chain NFT that
  // a physical sculpture extends). Rendered as a "Companion: {Title}" link
  // on the piece page so the catalogue can express the pairing.
  companionSlug?: string;
}

export interface Influence {
  name: string;
  movement: string;
  period: string;
  description: string;
  connectedArtists: string[];
  connectedCollections: string[];
}

